    public String createCallLog(String deviceId, String issueType) {
        //TODO if deviceID is called multiple times
        BigInteger timestamp = BigInteger.valueOf(System.currentTimeMillis());
        String id = Generators.timeBasedGenerator().generate().toString();
        aiCallLogRepository.insertAiCallLog(id, timestamp, null, issueType, "Device is offline", "High", "ongoing", Boolean.FALSE, deviceId, null);
        String assigneeResult = this.getAssignee(deviceId);
        if (assigneeResult == null) {
            ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(5);
            scheduler.schedule(() -> {
                String aiCalllogid = aiCallLogRepository.getAiCallLogIdByDeviceId(deviceId);
                if (aiCalllogid != null) {
                    System.out.println("id:" + id);
                    aiCallLogRepository.upsertStatus(id, null, true, null, "no-response");
                    aiCallLogHistoryRepository.insertAiCallLogHistoryState(Generators.timeBasedGenerator().generate().toString(), BigInteger.valueOf(System.currentTimeMillis()), "Technician not available", null, id, "no-response");
                    deviceService.updateDeviceDndAndSystemDndStatus(deviceId, false);
                    log.info("Auto-completed call {} as no-response", id);
                }
            }, 30, TimeUnit.SECONDS);
        }
        log.info(assigneeResult);
        return "Call log created with ID: " + id + ". " + assigneeResult;
    }

    public List<AiCallLogDTO> getallcallstatus(String username, String vdmsid, Integer pageNo, Integer pageSize, String searchKey, Boolean isCompleted) {
        Integer offset = (Integer) (pageSize * (pageNo - 1));
        log.info("Inside getallcallstatus with pageNo: {}, pageSize: {}, searchKey: {}", pageNo, pageSize, searchKey);
        String isCompletedString = isCompleted ? "1" : "0";
        List<AiCallLogDTO> callLogsDTOS = aiCallLogRepository.getAllAiCallLog(pageSize, offset, searchKey, isCompletedString);
        log.info("Retrieved {} call logs", callLogsDTOS.size());
        for (AiCallLogDTO callLogDTO : callLogsDTOS) {
            if (callLogDTO != null) {
                List<AiCallLogHistoryDTO> aiCallLogHistoryDTOS = aiCallLogHistoryRepository.getAiCallLogHistoryByAiCallLogId(callLogDTO.getId());
                log.info("Retrieved {} history records for call log ID: {}", aiCallLogHistoryDTOS.size(), callLogDTO.getId());
                callLogDTO.setAiCallLogHistory(aiCallLogHistoryDTOS);
                CallStatusDTO callStatusDTO = aiCallLogRepository.getStatusInformation(callLogDTO.getDeviceId());
                log.info("Retrieved CallStatusDTO for device ID: {}", callLogDTO.getDeviceId());
                callLogDTO.setCallStatus(callStatusDTO);
                log.info("Setting CallStatusDT0 status {}", callLogDTO.getCallStatus());
                log.info("Generated CallStatusDTO: {} ", callStatusDTO.getDeviceName());
            }
        }
        return callLogsDTOS;
    }

