    public String getAssignee(String deviceId) {
        WebClient webClient = WebClient.create();
        List<TechnicianDTO> technicians = technicianService.getAvailableTechnicianCountryCodePhoneByDeviceId(deviceId);
        System.out.println("Technicians: " + technicians.size());
        String vdmsId = "VDMS400";
        String aiCallLogId = aiCallLogRepository.getAiCallLogIdByDeviceId(deviceId);
        List<JSONObject> requestBodies = new ArrayList<>();
        if (technicians == null || technicians.isEmpty()) {
            log.info("Technician list is empty for device: {}", deviceId);
            return null;
        }
        DeviceDTO deviceDTO = this.getDeviceInfoFromDb(deviceId);
        try {
            JSONObject requestBody = createDeviceRequestBody(deviceDTO, "");
            // Add the same request body for each technician
            for (int i = 0; i < technicians.size(); i++) {
                requestBodies.add(requestBody);
            }
        } catch (JSONException e) {
            throw new RuntimeException("Failed to create request body", e);
        }
        // Process technicians sequentially
        processTechniciansSequentially(requestBodies, webClient, vdmsId, aiCallLogId, technicians, deviceDTO, 0);
        return "Assigned " + technicians.size() + " technician(s) to device " + deviceId;
        // }
    }

    private void processTechniciansSequentially(List<JSONObject> requestBodies, WebClient webClient, String vdmsId, String aiCallLogId, List<TechnicianDTO> technicians, DeviceDTO deviceDTO, int index) {
        if (index >= technicians.size()) {
            log.info("All technician calls complete.");
            return;
        }
        JSONObject requestBody = requestBodies.get(index);
        TechnicianDTO technician = technicians.get(index);
        String technicianName = technician.getName();
        String countryCode = technician.getCountryCode();
        String phone = technician.getPhone();
        String technicianId = technician.getId();
        String timezone = technician.getTimeZone();
        System.out.println("Timezone: " + timezone);
        System.out.println("Device Last Seen: " + deviceDTO.getLast_seen_on());
        System.out.println("Device ID: " + deviceDTO.getId());
        if (countryCode == null || phone == null || countryCode.isBlank() || phone.isBlank()) {
            log.error("Invalid country code or phone for technician: {}", technicianName);
            processTechniciansSequentially(requestBodies, webClient, vdmsId, aiCallLogId, technicians, deviceDTO, index + 1);
            return;
        }
        String contactNumber = countryCode + phone;
        log.info("Sending request for technician: {}", technicianName);
        log.info("Request Body:{} ", requestBody.toString());
        log.info("Parameters: vdmsId: {}, technicianId: {},technicianName:{}, contactNumber: {}, aiCallLogId: {}", vdmsId, technicianId, technicianName, contactNumber, aiCallLogId);
        String formattedDateTime = formatLastSeen(deviceDTO.getLast_seen_on(), timezone);
        log.info("Formatted last seen time: {}", formattedDateTime);
        // Call the API for the current technician
        Flux<JSONObject> responseFlux = apiCallService.sendDescription(requestBody, vdmsId, technicianId, technicianName, contactNumber, formattedDateTime, aiCallLogId);
        responseFlux.subscribe(json -> {
            log.info("Received response: {} ", json.toString());
            String result = insertCallResponse(json);
            log.info(result);
            // Check status to determine whether to stop or proceed
            boolean shouldStop = false;
            boolean isLastTechnician = index == technicians.size() - 1;
            if (json.has("events")) {
                try {
                    JSONArray events = json.getJSONArray("events");
                    long latestCreatedAt = Long.MIN_VALUE;
                    String latestStatus = null;
                    BigInteger latestTimestamp = null;
                    // Find the latest event and check for "accepted"
                    for (int i = 0; i < events.length(); i++) {
                        JSONObject event = events.getJSONObject(i);
                        String status = event.optString("status");
                        long createdAtMillis = event.optLong("created_at");
                        if (createdAtMillis > latestCreatedAt) {
                            latestCreatedAt = createdAtMillis;
                            latestStatus = status;
                            latestTimestamp = BigInteger.valueOf(createdAtMillis);
                        }
                        if (status.equalsIgnoreCase("accepted")) {
                            shouldStop = true;
                        }
                    }
                    // Map "incomplete" to "rejected" for last technician
                    String statusForUpsert = latestStatus;
                    if (latestStatus != null) {
                        if (latestStatus.equalsIgnoreCase("incomplete")) {
                            statusForUpsert = "rejected";
                            log.info("Mapping status \'incomplete\' to \'rejected\' for last technician, aiCallLogId={}", aiCallLogId);
                        } else if (latestStatus.equalsIgnoreCase("failed") || latestStatus.equalsIgnoreCase("busy")) {
                            statusForUpsert = "busy";
                            log.info("Mapping status \'busy\' for last technician, aiCallLogId={}", aiCallLogId);
                        } else if (latestStatus.equalsIgnoreCase("failed") || latestStatus.equalsIgnoreCase("no-answer")) {
                            statusForUpsert = "no-answer";
                            log.info("Mapping status \'no-answer\' for last technician, aiCallLogId={}", aiCallLogId);
                        }
                        // For the last technician, update with the latest event's status
                        if (isLastTechnician && latestStatus != null) {
                            log.info("Last technician, updating status to: {} for aiCallLogId={} with technicianId={}", statusForUpsert, aiCallLogId, technicianId);
                            String callFlowByDeviceid = callFlowRuleRepository.checkCallFlowByDeviceid(deviceDTO.getId());
                            Integer triggerCount = deviceConditionsService.getAlertCount(deviceDTO.getId());
                            if (callFlowByDeviceid != null) {
                                aiCallLogRepository.upsertStatus(aiCallLogId, latestTimestamp, Boolean.TRUE, technicianId, statusForUpsert);
                                if ((triggerCount == null || triggerCount <= 3) && statusForUpsert.equalsIgnoreCase("rejected") || statusForUpsert.equalsIgnoreCase("no-answer") || statusForUpsert.equalsIgnoreCase("busy")) {
                                    log.info("Triggering call flow for deviceId={} with status={} and aiCallLogId={}", deviceDTO.getId(), statusForUpsert, aiCallLogId);
                                    Set<DeviceConditionsDTO> deleteDeviceConditions = deviceConditionsService.getDeviceConditionsForAiCall("", "", "", deviceDTO.getId());
                                    deviceConditionsService.deleteDeviceConditions("", "", deleteDeviceConditions);
                                    this.triggerCallFlow(deviceDTO.getId(), statusForUpsert, aiCallLogId);
                                } else if (statusForUpsert.equalsIgnoreCase("accepted") && triggerCount <= 3) {
                                    Set<DeviceConditionsDTO> deleteDeviceConditions = deviceConditionsService.getDeviceConditionsForAiCall("", "", "", deviceDTO.getId());
                                    deviceConditionsService.deleteDeviceConditions("", "", deleteDeviceConditions); // Delete existing conditions
                                }
                            } else {
                                if (statusForUpsert.equalsIgnoreCase("accepted") && triggerCount <= 3) {
                                    aiCallLogRepository.upsertStatus(aiCallLogId, latestTimestamp, Boolean.TRUE, technicianId, "accepted");
                                    Set<DeviceConditionsDTO> deleteDeviceConditions = deviceConditionsService.getDeviceConditionsForAiCall("", "", "", deviceDTO.getId());
                                    deviceConditionsService.deleteDeviceConditions("", "", deleteDeviceConditions);
                                } else if ((triggerCount == null || triggerCount < 3) && (statusForUpsert.equalsIgnoreCase("rejected") || statusForUpsert.equalsIgnoreCase("no-answer") || statusForUpsert.equalsIgnoreCase("busy"))) {
                                    log.info("No call flow found for deviceId={} and status={}, keeping status as ongoing, aiCallLogId={}", deviceDTO.getId(), latestStatus, aiCallLogId);
                                    String status = aiCallLogRepository.getStatusRemovedByAiCallLogId(aiCallLogId);
                                    if (status.equalsIgnoreCase("Scheduler terminated")) {
                                        aiCallLogRepository.upsertStatus(aiCallLogId, latestTimestamp, Boolean.TRUE, technicianId, statusForUpsert);
                                    } else {
                                        Set<DeviceConditionsDTO> deviceConditions = createDeviceConditionsDTO(deviceDTO);
                                        deviceConditionsService.upsertDeviceConditionsForAiCall("", vdmsId, "", deviceConditions);
                                        log.info("Device is offline, updating status to ongoing for aiCallLogId={}", aiCallLogId);
                                    }
                                } else if (triggerCount == 3 && (statusForUpsert.equalsIgnoreCase("rejected") || statusForUpsert.equalsIgnoreCase("no-answer") || statusForUpsert.equalsIgnoreCase("busy"))) {
                                    log.info("No call flow found for deviceId={} and status={}, aiCallLogId={}", deviceDTO.getId(), latestStatus, aiCallLogId);
                                    aiCallLogRepository.upsertStatus(aiCallLogId, latestTimestamp, Boolean.TRUE, technicianId, statusForUpsert);
                                    Set<DeviceConditionsDTO> deleteDeviceConditions = deviceConditionsService.getDeviceConditionsForAiCall("", "", "", deviceDTO.getId());
                                    deviceConditionsService.deleteDeviceConditions("", "", deleteDeviceConditions);
                                }
                            }
                        }
                    }
                } catch (JSONException e) {
                    log.error("Error parsing events: {} ", e.getMessage());
                }
            }
            // Proceed to the next technician if not stopping
            if (!shouldStop) {
                Integer status = deviceService.getDeviceStatus(deviceDTO.getId());
                if (status != null && status == 0) {
                    processTechniciansSequentially(requestBodies, webClient, vdmsId, aiCallLogId, technicians, deviceDTO, index + 1);
                } else {
                    log.info("Device {} is online, skipping further technician calls.", deviceDTO.getId());
                    // Update device online status
                }
            }
        }, 
//                error -> {
//                    log.error("Error:{}", error.getMessage());
//                    // Proceed to the next technician
//                    processTechniciansSequentially(
//                            requestBodies, webClient, vdmsId, aiCallLogId, technicians, deviceDTO, index + 1
//                    );
//                }
        error -> {
            log.warn("Call to technician failed or timed out: {}", error.getMessage());
            Mono.delay(Duration.ofSeconds(90)).subscribeOn(Schedulers.boundedElastic()).subscribe(ignored -> {
                try {
                    String latestStatus = aiCallLogHistoryRepository.getLatestCallStatus(aiCallLogId, technicianId);
                    System.out.println("Latest status after 90 seconds: " + latestStatus);
                    Integer deviceStatus = deviceService.getDeviceStatus(deviceDTO.getId());
                    // stop escalation
                    if ("accepted".equalsIgnoreCase(latestStatus)) {
                        log.info("Technician accepted. Stopping escalation.");
                        return;
                    }
                    // do not escalate
                    if ("in-progress".equalsIgnoreCase(latestStatus)) {
                        log.info("Call still looks in-progress, waiting for final Twilio event...");
                        return;
                    }
                    // escalate
                    boolean shouldEscalate = latestStatus == null || "rejected".equalsIgnoreCase(latestStatus) || "no-answer".equalsIgnoreCase(latestStatus) || "busy".equalsIgnoreCase(latestStatus) || "failed".equalsIgnoreCase(latestStatus);
                    if (shouldEscalate && deviceStatus != null && deviceStatus == 0) {
                        log.info("Technician did not accept (status={}). Escalating to next technician.", latestStatus);
                        processTechniciansSequentially(requestBodies, webClient, vdmsId, aiCallLogId, technicians, deviceDTO, index + 1);
                    } else {
                        log.info("Device online or call accepted. Stopping escalation.");
                    }
                } catch (Exception ex) {
                    log.error("Error in 90-second handler: {}", ex.getMessage());
                }
            });
        });
    }

    //Socket insert method
    @Transactional
    public String insertCallResponse(org.json.JSONObject json) {
        try {
            List<String> historyIds = new ArrayList<>();
            String aiCallLogId = json.optString("ai_call_log_id");
            String technicianId = json.optString("technician_id", null);
            String technicianName = json.optString("technician_name");
            if (technicianId == null || technicianId.trim().isEmpty()) {
                technicianId = null;
            }
            boolean isWebSocketResponse = json.has("events") && json.getJSONArray("events").length() == 1;
            Set<String> insertedStatuses = new HashSet<>();
            if (json.has("events")) {
                org.json.JSONArray events = json.getJSONArray("events");
                for (int i = 0; i < events.length(); i++) {
                    org.json.JSONObject event = events.getJSONObject(i);
                    String id = event.optString("id");
                    String status = event.optString("status");
                    String description = event.optString("description");
                    long createdAtMillis = event.optLong("created_at");
                    BigInteger timestamp = BigInteger.valueOf(createdAtMillis);
                    // Check if the id already exists
                    if (!aiCallLogHistoryRepository.existsById(id)) {
                        if (isWebSocketResponse) {
                            if (!insertedStatuses.contains(status)) {
                                try {
                                    aiCallLogHistoryRepository.insertAiCallLogHistoryState(id, timestamp, description, technicianId, aiCallLogId, status);
                                    historyIds.add(id);
                                    insertedStatuses.add(status);
                                } catch (Exception e) {
                                    log.error("Error inserting history state for id={} : {}", id, e.getMessage(), e);
                                }
                            }
                        } else {
                            Set<String> existingStatuses = aiCallLogHistoryRepository.findStatusesByAiCallLogId(aiCallLogId);
                            if (existingStatuses == null) {
                                existingStatuses = new HashSet<>();
                            }
                            if (!existingStatuses.contains(status) && !insertedStatuses.contains(status)) {
                                try {
                                    aiCallLogHistoryRepository.insertAiCallLogHistoryState(id, timestamp, description, technicianId, aiCallLogId, status);
                                    historyIds.add(id);
                                    insertedStatuses.add(status);
                                } catch (Exception e) {
                                    log.error("Error upserting history state for id={} : {}", id, e.getMessage(), e);
                                }
                            }
                        }
                    }
                    if (technicianName != null && !technicianName.equalsIgnoreCase("manager")) {
                        String device_id = aiCallLogRepository.getDeviceIdByAiCallLogId(aiCallLogId);
                        if (status.equalsIgnoreCase("accepted")) {
                            log.info("Updating status to: {} for aiCallLogId={} with technicianId={}", status, aiCallLogId, technicianId);
                            aiCallLogRepository.upsertStatus(aiCallLogId, timestamp, Boolean.TRUE, technicianId, status);
                            Set<DeviceConditionsDTO> deleteDeviceConditions = deviceConditionsService.getDeviceConditionsForAiCall("", "", "", device_id);
                            if (deleteDeviceConditions != null && !deleteDeviceConditions.isEmpty()) {
                                log.info("Deleting device conditions for device_id={} and aiCallLogId={}", device_id, aiCallLogId);
                                // Delete existing conditions
                                deviceConditionsService.deleteDeviceConditions("", "", deleteDeviceConditions);
                            }
                        }
                        String completedAiCallLogId = aiCallLogRepository.getAiCallLogIdByIsCompleted(aiCallLogId, Boolean.TRUE);
                        if (completedAiCallLogId != null && !completedAiCallLogId.isEmpty()) {
                            if (status != null) {
                                String statusForUpsert;
                                // Map input status to upsert status
                                switch (status.toLowerCase()) {
                                case "incomplete": 
                                    statusForUpsert = "rejected";
                                    log.info("Mapping \'incomplete\' to \'rejected\' for aiCallLogId={}", aiCallLogId);
                                    break;
                                case "failed": 
                                case "busy": 
                                    statusForUpsert = "busy";
                                    log.info("Mapping \'{}\' to \'busy\' for aiCallLogId={}", status, aiCallLogId);
                                    break;
                                case "no-answer": 
                                    statusForUpsert = "no-answer";
                                    log.info("Mapping \'{}\' to \'no-answer\' for aiCallLogId={}", status, aiCallLogId);
                                    break;
                                default: 
                                    statusForUpsert = status.toLowerCase();
                                    log.info("Using original status \'{}\' for aiCallLogId={}", statusForUpsert, aiCallLogId);
                                    break;
                                }
                                // Always call upsert
                                if ("rejected".equalsIgnoreCase(statusForUpsert) || "busy".equalsIgnoreCase(statusForUpsert) || "no-answer".equalsIgnoreCase(statusForUpsert)) {
                                    aiCallLogRepository.upsertStatus(aiCallLogId, timestamp, Boolean.TRUE, technicianId, statusForUpsert);
                                    Set<DeviceConditionsDTO> deleteDeviceConditions = deviceConditionsService.getDeviceConditionsForAiCall("", "", "", device_id);
                                    if (deleteDeviceConditions != null && !deleteDeviceConditions.isEmpty()) {
                                        log.info("Deleting device conditions for device_id={} and aiCallLogId={}", device_id, aiCallLogId);
                                        deviceConditionsService.deleteDeviceConditions("", "", deleteDeviceConditions);
                                    }
                                }
                            }
                        }
                    }
                }
            }
            // Notify socket for inserted history records
            for (String id : historyIds) {
                try {
                    socketService.socketAiCallLogHistoryUpdate(id);
                } catch (Exception e) {
                    log.error("Socket update failed for id={} : {}", id, e.getMessage(), e);
                }
            }
        } catch (Exception e) {
            log.error("Failed to parse call response JSON: {}", e.getMessage(), e);
        }
        return "Call response inserted successfully";
    }

