    private String formatLastSeen(String lastSeen, String timezone) {
        if (lastSeen == null || lastSeen.isBlank()) {
            return "Last seen time not available";
        }
        try {
            String cleanedLastSeen = lastSeen.split("\\.")[0];
            long epochMillis = Long.parseLong(cleanedLastSeen);
            Instant instant = Instant.ofEpochMilli(epochMillis);
            ZonedDateTime zdt = instant.atZone(ZoneId.of(timezone));
            DateTimeFormatter formatter = DateTimeFormatter.ofPattern("MMMM d, yyyy, h:mm a z");
            return zdt.format(formatter);
        } catch (NumberFormatException | ArrayIndexOutOfBoundsException | DateTimeException e) {
            log.error("Error formatting last seen time: " + lastSeen + ", timezone: " + timezone + ": " + e.getMessage());
            return "Invalid";
        }
    }

    private Set<DeviceConditionsDTO> createDeviceConditionsDTO(DeviceDTO deviceDTO) {
        Set<DeviceConditionsDTO> deviceConditions = new HashSet<>();
        DeviceConditionsDTO condition = new DeviceConditionsDTO();
        condition.setDevice_id(deviceDTO.getId());
        condition.setAlert_condition("device_offline_ai_call_alert");
        condition.setTrigger_time(1800); // 30 - 1800 minutes in seconds
        condition.setPriority("High");
        condition.setStart_time("00:00");
        condition.setEnd_time("23:59");
        condition.setMax_alert_count(3);
        condition.setAlert_message("Device is offline");
        condition.setAlert_count_enabled(1);
        deviceConditions.add(condition);
        return deviceConditions;
    }

    public void updateDeviceOnlineStatus(String id, Integer status, String deviceConditionId) {
        System.out.println("*************Updating device online status for device ID: " + id + " with status: " + status);
        String aiCallLogId = aiCallLogRepository.getAiCallLogIdByDeviceId(id);
        String aiCallLogHistoryId = Generators.timeBasedGenerator().generate().toString();
        Integer alertCount = deviceConditionsService.getAlertCount(id);
        BigInteger createdAt = BigInteger.valueOf(System.currentTimeMillis());
        if (deviceConditionId != null && !deviceConditionId.isEmpty()) {
            if (aiCallLogId != null) {
                log.info("Updating device online status for aiCallLogId: {} with status: {}", aiCallLogId, status);
                aiCallLogHistoryRepository.insertAiCallLogHistoryState(aiCallLogHistoryId, createdAt, "Device online", null, aiCallLogId, "Scheduler terminated");
                socketService.socketAiCallLogOngoingHistoryUpdate(aiCallLogHistoryId);
                String callFlowByDeviceId = callFlowRuleRepository.checkCallFlowByDeviceid(id);
                if (alertCount != 3 || callFlowByDeviceId.isEmpty()) {
                    aiCallLogRepository.upsertStatus(aiCallLogId, null, Boolean.TRUE, null, "Scheduler terminated");
                }
                deviceService.getDeviceDndAndSystemDndStatus(id, true);
                Set<DeviceConditionsDTO> deleteDeviceConditions = deviceConditionsService.getDeviceConditionsForAiCall("", "", "", id);
                deviceConditionsService.deleteDeviceConditions("", "", deleteDeviceConditions);
            } else {
                log.info("No aiCallLogId found for device ID: {}. Creating new call log.", id);
            }
        } else {
            // If deviceConditionId is null or empty, we assume the device is online and update the status accordingly
            if (aiCallLogId != null) {
                int historyCount = aiCallLogHistoryRepository.countByAiCallLogId(aiCallLogId);
                if (historyCount == 0) {
                    aiCallLogRepository.upsertStatus(aiCallLogId, null, Boolean.TRUE, null, "Device Online");
                    deviceService.getDeviceDndAndSystemDndStatus(id, true);
                }
                aiCallLogHistoryRepository.insertAiCallLogHistoryState(aiCallLogHistoryId, createdAt, "Device online", null, aiCallLogId, "Device Online");
                socketService.socketAiCallLogOngoingHistoryUpdate(aiCallLogHistoryId);
            }
        }
    }

