    public List<CallFlowRuleDTO> getCallFlow(String username, String vdmsid, Integer pageno, Integer pagesize, String searchkey) {
        Integer offset = pagesize * (pageno - 1);
        List<CallFlowRuleDTO> callFlowRuleDTOS = callFlowRuleRepository.getAllCallFlowRules(offset, pagesize, searchkey);
        for (CallFlowRuleDTO callFlowRuleDTO : callFlowRuleDTOS) {
            List<CallFlowRuleConditionDTO> conditionDTOList = getCallFlowRuleConditionsByCallFlowRuleId(callFlowRuleDTO.getId());
            callFlowRuleDTO.setCallFlowRuleConditions(conditionDTOList);
        }
        return callFlowRuleDTOS;
    }

    public void deleteCallFlowById(String username, String vdmsid, Set<String> callFlowRuleIds) {
        for (String callFlowRuleId : callFlowRuleIds) {
            callFlowRuleRepository.deleteById(callFlowRuleId);
        }
    }

    public ResponseEntity<ResponseDTO> upsertCallFlow(CallFlowRuleDTO callFlowRuleDTO, String username, String vdmsid) {
        BigInteger timestamp = BigInteger.valueOf(System.currentTimeMillis());
        log.info("Processing DTO: {}", callFlowRuleDTO);
        List<String> newCallFlowRuleConditionIds = new ArrayList<>();
        List<CallFlowRuleConditionDTO> existingCallFlowRuleConditionDTOList = new ArrayList<>();
        List<String> callFlowRuleConditionToBeDeleted = new ArrayList<>();
        Set<String> requestCriteriaSet = new HashSet<>();
        if (callFlowRuleDTO != null) {
            if (callFlowRuleDTO.getId() == null) {
                callFlowRuleDTO.setId(Generators.timeBasedGenerator().generate().toString());
            } else {
                existingCallFlowRuleConditionDTOList = getCallFlowRuleConditionsByCallFlowRuleId(callFlowRuleDTO.getId());
            }
            List<CallFlowRuleConditionDTO> callFlowRuleConditionDTOList = callFlowRuleDTO.getCallFlowRuleConditions();
            if (!callFlowRuleConditionDTOList.isEmpty()) {
                for (CallFlowRuleConditionDTO conditionDTO : callFlowRuleConditionDTOList) {
                    String criteria = conditionDTO.getCriteria();
                    if (criteria == null) continue;
                    if (!requestCriteriaSet.add(criteria)) {
                        ResponseDTO error = new ResponseDTO("Conflict: Duplicate criteria detected in the request - \'" + criteria + "\' already exists.", 409, null, false, timestamp);
                        return ResponseEntity.status(HttpStatus.CONFLICT).body(error);
                    }
                    if (conditionDTO.getId() != null) {
                        newCallFlowRuleConditionIds.add(conditionDTO.getId());
                    }
                }
            }
            for (CallFlowRuleConditionDTO callFlowRuleCondition : existingCallFlowRuleConditionDTOList) {
                if (callFlowRuleCondition.getId() != null && !newCallFlowRuleConditionIds.contains(callFlowRuleCondition.getId())) {
                    callFlowRuleConditionToBeDeleted.add(callFlowRuleCondition.getId());
                }
            }
            callFlowRuleRepository.upsertAiCallFlow(callFlowRuleDTO.getId(), callFlowRuleDTO.getName(), username, timestamp, username, timestamp, callFlowRuleDTO.getDeviceId());
            deleteCallFlowConditions(callFlowRuleDTO, callFlowRuleConditionToBeDeleted);
            upsertCallFlowConditions(callFlowRuleDTO, callFlowRuleConditionDTOList);
            ResponseDTO success = new ResponseDTO("Call flow rule and conditions updated successfully.", 200, true, timestamp);
            return ResponseEntity.ok(success);
        }
        ResponseDTO error = new ResponseDTO("Invalid request: Call flow data must not be null", 400, false, timestamp);
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(error);
    }

