    public void upsertCallFlowConditions(CallFlowRuleDTO callFlowRuleDTO, List<CallFlowRuleConditionDTO> callFlowRuleConditionDTOs) {
        if (callFlowRuleDTO != null && callFlowRuleConditionDTOs != null && !callFlowRuleConditionDTOs.isEmpty()) {
            for (CallFlowRuleConditionDTO callFlowRuleConditionDTO : callFlowRuleConditionDTOs) {
                if (callFlowRuleConditionDTO.getId() == null) {
                    callFlowRuleConditionDTO.setId(Generators.timeBasedGenerator().generate().toString());
                }
                callFlowRuleConditionRepository.upsertCallFlowRuleCondition(callFlowRuleConditionDTO.getId(), callFlowRuleConditionDTO.getCriteria(), callFlowRuleConditionDTO.getActionType(), callFlowRuleConditionDTO.getActionValue(), callFlowRuleConditionDTO.getActionMessage(), callFlowRuleDTO.getId());
            }
        }
    }

