    public List<CallFlowRuleDTO> getCallFlowByDeviceId(String deviceId) {
        List<CallFlowRuleDTO> callFlowRuleDTOS = new ArrayList<>();
        try {
            if (deviceId != null && !deviceId.trim().isEmpty()) {
                List<CallFlowRuleDTO> fetchedRules = callFlowRuleRepository.getCallFlowByDeviceId(deviceId);
                if (fetchedRules != null) {
                    for (CallFlowRuleDTO fetchedRule : fetchedRules) {
                        if (fetchedRule != null && fetchedRule.getId() != null) {
                            try {
                                List<CallFlowRuleConditionDTO> conditions = getCallFlowRuleConditionsByCallFlowRuleId(fetchedRule.getId());
                                fetchedRule.setCallFlowRuleConditions(conditions != null ? conditions : Collections.emptyList());
                            } catch (Exception e) {
                                log.error("Error fetching conditions for rule ID: {}", fetchedRule.getId(), e);
                                fetchedRule.setCallFlowRuleConditions(Collections.emptyList());
                            }
                        }
                        callFlowRuleDTOS.add(fetchedRule);
                    }
                }
            } else {
                log.warn("Device ID is null or empty.");
            }
        } catch (Exception e) {
            log.error("Unexpected error in getCallFlowByDeviceId for device ID: {}", deviceId, e);
        }
        return callFlowRuleDTOS;
    }

    public List<CallFlowRuleDTO> getCallFlowByDeviceIdAndCriteria(String deviceId, String criteria) {
        if (deviceId == null || deviceId.trim().isEmpty()) {
            log.warn("Device ID is null or empty.");
            return Collections.emptyList();
        }
        List<CallFlowRuleDTO> fetchedRules;
        try {
            fetchedRules = callFlowRuleRepository.getCallFlowByDeviceId(deviceId);
        } catch (Exception e) {
            log.error("Error fetching call flow rules for device ID: {}", deviceId, e);
            return Collections.emptyList();
        }
        if (fetchedRules == null || fetchedRules.isEmpty()) {
            return Collections.emptyList();
        }
        for (CallFlowRuleDTO rule : fetchedRules) {
            if (rule != null && rule.getId() != null) {
                try {
                    List<CallFlowRuleConditionDTO> conditions = getCallFlowRuleConditionByRuleIdAndCriteria(rule.getId(), criteria);
                    rule.setCallFlowRuleConditions(conditions != null ? conditions : Collections.emptyList());
                } catch (Exception e) {
                    log.error("Error fetching conditions for rule ID: {}", rule.getId(), e);
                    rule.setCallFlowRuleConditions(Collections.emptyList());
                }
            }
        }
        return fetchedRules;
    }

    public void triggerCallFlow(String deviceId, String criteria, String callLogId) {
        List<CallFlowRuleDTO> callFlowRuleDTOS = getCallFlowByDeviceIdAndCriteria(deviceId, criteria);
        String date = "";
        String time = "";
        VdmsDTO vdms = new VdmsDTO();
        vdms.setId("VDMS400");
        DeviceDTO deviceDTO = this.getDeviceInfoFromDb(deviceId);
        String formattedDateTime = formatLastSeen(deviceDTO.getLast_seen_on(), vdms.getTimezone());
        String[] parts = formattedDateTime.split(",\\s+");
        if (parts.length >= 3) {
            date = parts[0] + ", " + parts[1]; // "June 16, 2025"
            time = parts[2]; // "4:30 PM IST"
        } else {
            log.error("Could not split date and time correctly.");
        }
        if (callFlowRuleDTOS != null && !callFlowRuleDTOS.isEmpty()) {
            for (CallFlowRuleDTO callFlowRuleDTO : callFlowRuleDTOS) {
                if (callFlowRuleDTO.getCallFlowRuleConditions() != null && !callFlowRuleDTO.getCallFlowRuleConditions().isEmpty()) {
                    for (CallFlowRuleConditionDTO condition : callFlowRuleDTO.getCallFlowRuleConditions()) {
                        log.info("Processing condition: {} for device: {}", condition.getCriteria(), callFlowRuleDTO.getDeviceName());
                        switch (condition.getActionType()) {
                        case "Re-route": 
                            log.info("Re-routing call for device: {} with action value: {}", callFlowRuleDTO.getDeviceName(), condition.getActionValue());
                            String phone = condition.getActionValue();
                            if (phone != null && !phone.startsWith("+")) {
                                phone = "+" + phone;
                            }
                            // String response = makeManagerCall(deviceId, condition.getActionValue(), callLogId);
                            // log.info("Re-routing {}",response);
                            makeManagerCall(deviceId, phone, callLogId).subscribe(response -> log.info("Re-routing {}", response), error -> log.error("Error in manager call: {}", error.getMessage(), error));
                            break;
                        case "Email": 
                            com.alibaba.fastjson.JSONObject emailRequestBody = new com.alibaba.fastjson.JSONObject();
                            emailRequestBody.put("date", date);
                            emailRequestBody.put("asset_name", callFlowRuleDTO.getDeviceName());
                            emailRequestBody.put("time", time);
                            emailRequestBody.put("email", condition.getActionValue());
                            emailRequestBody.put("message", condition.getActionMessage());
                            emailRequestBody.put("property_name", vdms.getProperty_name());
                            emailRequestBody.put("vdms_id", vdms.getId());
                            emailRequestBody.put("alert_type", "email");
                            log.info("Sending email request body: {}", emailRequestBody);
                            ResponseEntity<String> emailResponse = apiCallService.sendCallFlowMail(emailRequestBody);
                            if (emailResponse != null && emailResponse.getStatusCodeValue() == 200) {
                                log.info("Email sent successfully");
                                insertCallFlowResponse("Email sent to " + condition.getActionValue(), "Email sent to " + condition.getActionValue(), callLogId);
                            } else {
                                log.error("Failed to send email {}", emailResponse);
                            }
                            break;
                        case "SMS": 
                            log.info("Sending SMS for device: {} to {} with message: {}", callFlowRuleDTO.getDeviceName(), condition.getActionValue(), condition.getActionMessage());
                            String phoneNo = condition.getActionValue();
                            if (phoneNo != null && !phoneNo.startsWith("+")) {
                                phoneNo = "+" + phoneNo;
                            }
                            com.alibaba.fastjson.JSONObject messageBody = new com.alibaba.fastjson.JSONObject();
                            messageBody.put("date", date);
                            messageBody.put("asset_name", callFlowRuleDTO.getDeviceName());
                            messageBody.put("time", time);
                            messageBody.put("email", condition.getActionValue());
                            messageBody.put("phone", phoneNo);
                            messageBody.put("message", condition.getActionMessage());
                            messageBody.put("property_name", vdms.getProperty_name());
                            messageBody.put("vdms_id", vdms.getId());
                            messageBody.put("alert_type", "sms");
                            log.info("Sending SMS request body: {}", messageBody);
                            ResponseEntity<String> smsResponse = apiCallService.sendCallFlowMessage(messageBody);
                            if (smsResponse != null && smsResponse.getStatusCodeValue() == 200) {
                                log.info("SMS sent successfully");
                                insertCallFlowResponse("SMS sent to " + phoneNo, "SMS sent to " + phoneNo, callLogId);
                            } else {
                                log.error("Failed to send SMS: {}", smsResponse);
                            }
                            break;
                        default: 
                            log.warn("Unknown action type: {} for device: {}", condition.getActionType(), callFlowRuleDTO.getDeviceName());
                        }
                    }
                } else {
                    log.warn("No call flow rules found for device ID: {} with criteria: {}", deviceId, criteria);
                }
            }
        } else {
            log.warn("No call flow rules found for device ID: {} with criteria: {}", deviceId, criteria);
        }
    }

    public void insertCallFlowResponse(String description, String state, String aiCallLogId) {
        String id = Generators.timeBasedGenerator().generate().toString();
        aiCallLogHistoryRepository.insertAiCallLogHistoryState(id, BigInteger.valueOf(System.currentTimeMillis()), description, null, aiCallLogId, state);
        try {
            socketService.socketAiCallLogHistoryUpdate(id);
        } catch (Exception e) {
            log.error("Socket update failed for id={} : {}", id, e.getMessage(), e);
        }
    }

    public Mono<String> makeManagerCall(String deviceId, String phoneNo, String aiCallLogId) {
        try {
            VdmsDTO vdmsDTO = new VdmsDTO();
            vdmsDTO.setId("VDMS400");
            DeviceDTO deviceDTO = this.getDeviceInfoFromDb(deviceId);
            String issueType = aiCallLogRepository.getAiCallLogIssueTypeByAiCallLogId(aiCallLogId);
            JSONObject requestBody = createDeviceRequestBody(deviceDTO, issueType);
            String formattedDateTime = formatLastSeen(deviceDTO.getLast_seen_on(), vdmsDTO.getTimezone());
            log.info("Sending request to Twilio: {} vdms id :{} contact number : {} ai CallLogId :{} ", requestBody.toString(), vdmsDTO.getId(), phoneNo, aiCallLogId);
            return apiCallService.sendDescription(requestBody, vdmsDTO.getId(), null, "manager", phoneNo, formattedDateTime, aiCallLogId).collectList().flatMap(responses -> {
                try {
                    if (responses == null || responses.isEmpty()) {
                        log.warn("No response received from manager call.");
                        return Mono.just("failed");
                    }
                    for (JSONObject json : responses) {
                        log.info("Received response manager call: {}", json.toString());
                        String result = insertCallResponse(json);
                        log.info(result);
                        if (json.has("events")) {
                            JSONArray events = json.getJSONArray("events");
                            for (int i = 0; i < events.length(); i++) {
                                JSONObject event = events.getJSONObject(i);
                                String status = event.optString("status");
                                log.info("Manager call {} for deviceId={} with aiCallLogId={}", status, deviceId, aiCallLogId);
                            }
                        }
                    }
                    return Mono.just("success");
                } catch (JSONException e) {
                    log.error("JSON parsing error during manager call: {}", e.getMessage(), e);
                    return Mono.just("failed");
                }
            }).onErrorResume(e -> {
                log.error("Error occurred during manager call (reactive pipeline): {}", e.getMessage(), e);
                return Mono.just("failed");
            });
        } catch (Exception e) {
            log.error("Error occurred during manager call (outer catch): {}", e.getMessage(), e);
            return Mono.just("failed");
        }
    }
